class Solution:
    def stoneGame(self, piles):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(None)
        def best(i, j):
            if i > j:
                return 0
            return max(piles[i] - best(i + 1, j), piles[j] - best(i, j - 1))
        return best(0, len(piles) - 1) > 0

